/**
 * CSV Parser Library for TypeScript
 * Handles parsing, validation, filtering, and aggregation of CSV data
 */

/**
 * Options for CSV parsing
 */
export interface CSVOptions {
  /** Field delimiter, default: ',' */
  delimiter?: string;
  /** Quote character, default: '"' */
  quote?: string;
  /** Line separator, default: '\n' or '\r\n' */
  lineSeparator?: string;
}

/**
 * Represents a parsing error
 */
export interface CSVError {
  row: number;
  message: string;
}

/**
 * Result object returned from parsing
 */
export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

/**
 * Coerce a value to its appropriate type
 */
function coerceType(value: string): any {
  // Check for null values
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Check for boolean values
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Check for numeric values
  if (/^-?\d+(\.\d+)?$/.test(value)) {
    const num = parseFloat(value);
    if (!isNaN(num)) {
      return num;
    }
  }

  // Return as string by default
  return value;
}

/**
 * Parse a CSV string into structured data
 */
export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? (/\r\n/.test(input) ? '\r\n' : '\n');

  const errors: CSVError[] = [];
  let rows: Record<string, any>[] = [];
  let headers: string[] = [];

  if (!input || input.trim() === '') {
    return createResult([], [], errors);
  }

  // Split by line separator
  const lines = input.split(lineSeparator);

  // Parse each line into fields, handling quoted fields
  const parsedLines: string[][] = [];
  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    // Skip empty lines
    if (!line || line.trim() === '') {
      continue;
    }

    try {
      const fields = parseFields(line, delimiter, quote);
      parsedLines.push(fields);
    } catch (error) {
      errors.push({
        row: lineIndex + 1,
        message: error instanceof Error ? error.message : 'Unknown parsing error'
      });
    }
  }

  if (parsedLines.length === 0) {
    return createResult([], [], errors);
  }

  // First row is headers
  headers = parsedLines[0];

  // Parse remaining rows
  for (let i = 1; i < parsedLines.length; i++) {
    const fields = parsedLines[i];
    const row: Record<string, any> = {};

    // Check for column count mismatch
    if (fields.length !== headers.length) {
      errors.push({
        row: i + 1,
        message: `Column count mismatch: expected ${headers.length}, got ${fields.length}`
      });
      continue;
    }

    // Map fields to header names with type coercion
    for (let j = 0; j < headers.length; j++) {
      const header = headers[j];
      const value = fields[j] ?? '';
      row[header] = coerceType(value);
    }

    rows.push(row);
  }

  return createResult(rows, headers, errors);
}

/**
 * Parse a single CSV line into fields, handling quoted fields
 */
function parseFields(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let current = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = line[i + 1];

    if (char === quote) {
      if (inQuotes && nextChar === quote) {
        // Escaped quote (two quotes = one literal)
        current += quote;
        i += 2;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      // Field delimiter
      fields.push(current);
      current = '';
      i++;
    } else {
      // Regular character
      current += char;
      i++;
    }
  }

  // Add the last field
  fields.push(current);

  // Validate that quotes are properly closed
  if (inQuotes) {
    throw new Error('Unclosed quoted field');
  }

  return fields;
}

/**
 * Create a CSVResult object with methods
 */
function createResult(
  rows: Record<string, any>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult {
      const filtered = rows.filter(predicate);
      return createResult(filtered, headers, errors);
    },

    sum(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column not found: ${column}`);
      }
      return rows.reduce((acc, row) => {
        const value = row[column];
        const num = typeof value === 'number' ? value : 0;
        return acc + num;
      }, 0);
    },

    average(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column not found: ${column}`);
      }
      const numericValues = rows
        .map(row => row[column])
        .filter((v): v is number => typeof v === 'number');

      if (numericValues.length === 0) {
        return 0;
      }

      const sum = numericValues.reduce((acc, val) => acc + val, 0);
      return sum / numericValues.length;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<any, Record<string, any>[]> {
      if (!headers.includes(column)) {
        throw new Error(`Column not found: ${column}`);
      }

      const groups = new Map<any, Record<string, any>[]>();

      for (const row of rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }

      return groups;
    }
  };
}

/**
 * Comprehensive test suite for CSV Parser
 * Tests all features without any external testing framework
 */

import { parseCSV, CSVResult } from './csv-parser';

/**
 * Assertion helper
 */
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

/**
 * Deep equality check for objects and arrays
 */
function deepEqual(a: any, b: any): boolean {
  if (a === b) return true;
  if (a == null || b == null) return false;
  if (typeof a !== typeof b) return false;

  if (typeof a === 'object') {
    if (Array.isArray(a) && Array.isArray(b)) {
      if (a.length !== b.length) return false;
      return a.every((val, idx) => deepEqual(val, b[idx]));
    }
    const keysA = Object.keys(a);
    const keysB = Object.keys(b);
    if (keysA.length !== keysB.length) return false;
    return keysA.every(key => deepEqual(a[key], b[key]));
  }

  return false;
}

/**
 * Test runner
 */
function test(name: string, fn: () => void): void {
  try {
    fn();
    console.log(`✓ ${name}`);
  } catch (error) {
    console.error(`✗ ${name}`);
    console.error(`  ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}

// ============================================================================
// TESTS
// ============================================================================

test('Basic parsing - simple CSV with headers and data', () => {
  const csv = 'name,age,city\nJohn,30,NYC\nJane,25,LA';
  const result = parseCSV(csv);

  assert(result.headers.length === 3, 'Should have 3 headers');
  assert(deepEqual(result.headers, ['name', 'age', 'city']), 'Headers should match');
  assert(result.rows.length === 2, 'Should have 2 rows');
  assert(result.rows[0].name === 'John', 'First row name should be John');
  assert(result.rows[1].name === 'Jane', 'Second row name should be Jane');
  assert(result.errors.length === 0, 'Should have no errors');
});

test('Basic parsing - single column', () => {
  const csv = 'name\nAlice\nBob\nCharlie';
  const result = parseCSV(csv);

  assert(result.headers.length === 1, 'Should have 1 header');
  assert(result.rows.length === 3, 'Should have 3 rows');
  assert(result.rows[0].name === 'Alice', 'First row should be Alice');
  assert(result.rows[2].name === 'Charlie', 'Third row should be Charlie');
});

test('Basic parsing - single row', () => {
  const csv = 'a,b,c\n1,2,3';
  const result = parseCSV(csv);

  assert(result.rows.length === 1, 'Should have 1 row');
  assert(result.rows[0].a === 1, 'Should coerce to number');
});

test('Quoted fields - field with comma inside quotes', () => {
  const csv = 'name,description\nJohn,"A person, born in 1990"\nJane,"Another person, different age"';
  const result = parseCSV(csv);

  assert(result.rows.length === 2, 'Should have 2 rows');
  assert(
    result.rows[0].description === 'A person, born in 1990',
    'Should parse comma inside quotes correctly'
  );
  assert(
    result.rows[1].description === 'Another person, different age',
    'Should handle multiple commas in quoted field'
  );
});

test('Quoted fields - field with quote at start and end', () => {
  const csv = 'data\n"hello"\n"world"';
  const result = parseCSV(csv);

  assert(result.rows.length === 2, 'Should have 2 rows');
  assert(result.rows[0].data === 'hello', 'Should remove surrounding quotes');
  assert(result.rows[1].data === 'world', 'Should handle quoted fields');
});

test('Quoted fields - field with multiple delimiters inside', () => {
  const csv = 'text\n"a,b,c,d,e"\n"f,g"';
  const result = parseCSV(csv);

  assert(result.rows[0].text === 'a,b,c,d,e', 'Should preserve commas inside quotes');
  assert(result.rows[1].text === 'f,g', 'Should handle another quoted field');
});

test('Escaped quotes - double quotes = single quote', () => {
  const csv = 'message\n"She said ""hello"""\n"He replied ""goodbye"""';
  const result = parseCSV(csv);

  assert(result.rows.length === 2, 'Should have 2 rows');
  assert(result.rows[0].message === 'She said "hello"', 'Should unescape double quotes');
  assert(result.rows[1].message === 'He replied "goodbye"', 'Should handle escaped quotes');
});

test('Escaped quotes - mixed content with escaped quotes', () => {
  const csv = 'text\n"Quote: ""Hi, how are you?"""\n"Another ""test"" here"';
  const result = parseCSV(csv);

  assert(
    result.rows[0].text === 'Quote: "Hi, how are you?"',
    'Should handle escaped quotes with punctuation'
  );
  assert(
    result.rows[1].text === 'Another "test" here',
    'Should handle multiple escaped quotes'
  );
});

test('Escaped quotes - only escaped quotes', () => {
  const csv = 'x\n""""\n"""""""';
  const result = parseCSV(csv);

  assert(result.rows[0].x === '"', 'Four quotes should become one quote');
  assert(result.rows[1].x === '"""', 'Seven quotes should become three quotes');
});

test('Custom delimiter - semicolon', () => {
  const csv = 'a;b;c\n1;2;3';
  const result = parseCSV(csv, { delimiter: ';' });

  assert(result.headers.length === 3, 'Should have 3 headers');
  assert(deepEqual(result.headers, ['a', 'b', 'c']), 'Headers should match');
  assert(result.rows[0].a === 1, 'Should parse with semicolon delimiter');
});

test('Custom delimiter - pipe', () => {
  const csv = 'name|value\ntest|123';
  const result = parseCSV(csv, { delimiter: '|' });

  assert(result.headers[0] === 'name', 'First header should be "name"');
  assert(result.rows[0].name === 'test', 'Should use pipe delimiter');
});

test('Custom delimiter - tab', () => {
  const csv = 'a\tb\tc\n1\t2\t3';
  const result = parseCSV(csv, { delimiter: '\t' });

  assert(result.headers.length === 3, 'Should have 3 headers');
  assert(result.rows[0].a === 1, 'Should parse tab-delimited data');
});

test('Custom quote character - single quote', () => {
  const csv = "name,description\nJohn,'A, B, C'";
  const result = parseCSV(csv, { quote: "'" });

  assert(result.rows[0].description === 'A, B, C', 'Should use single quote');
});

test('Custom quote character - backtick', () => {
  const csv = 'a,b\n`hello,world`,test';
  const result = parseCSV(csv, { quote: '`' });

  assert(result.rows[0].a === 'hello,world', 'Should use backtick as quote');
});

test('Custom quote character - escaped with custom quote', () => {
  const csv = "text\n'It''s working'";
  const result = parseCSV(csv, { quote: "'" });

  assert(result.rows[0].text === "It's working", 'Should escape custom quote char');
});

test('Custom line separator - CRLF', () => {
  const csv = 'a,b\r\n1,2\r\n3,4';
  const result = parseCSV(csv);

  assert(result.rows.length === 2, 'Should handle CRLF line separators');
  assert(result.rows[0].a === 1, 'First row should be correct');
  assert(result.rows[1].a === 3, 'Second row should be correct');
});

test('Custom line separator - custom separator', () => {
  const csv = 'a,b|1,2|3,4';
  const result = parseCSV(csv, { lineSeparator: '|' });

  assert(result.rows.length === 2, 'Should use custom line separator');
  assert(result.rows[0].a === 1, 'First row should be correct');
});

test('Type coercion - integers', () => {
  const csv = 'num\n42\n-100\n0';
  const result = parseCSV(csv);

  assert(result.rows[0].num === 42, 'Should coerce to integer');
  assert(result.rows[1].num === -100, 'Should handle negative integers');
  assert(result.rows[2].num === 0, 'Should handle zero');
  assert(typeof result.rows[0].num === 'number', 'Type should be number');
});

test('Type coercion - floats', () => {
  const csv = 'value\n3.14\n-2.5\n0.0';
  const result = parseCSV(csv);

  assert(result.rows[0].value === 3.14, 'Should coerce to float');
  assert(result.rows[1].value === -2.5, 'Should handle negative floats');
  assert(result.rows[2].value === 0.0, 'Should handle zero float');
});

test('Type coercion - booleans true', () => {
  const csv = 'flag\ntrue\nTRUE\nTrue';
  const result = parseCSV(csv);

  assert(result.rows[0].flag === true, 'Should coerce "true"');
  assert(result.rows[1].flag === true, 'Should coerce "TRUE"');
  assert(result.rows[2].flag === true, 'Should coerce "True"');
  assert(typeof result.rows[0].flag === 'boolean', 'Type should be boolean');
});

test('Type coercion - booleans false', () => {
  const csv = 'flag\nfalse\nFALSE\nFalse';
  const result = parseCSV(csv);

  assert(result.rows[0].flag === false, 'Should coerce "false"');
  assert(result.rows[1].flag === false, 'Should coerce "FALSE"');
  assert(result.rows[2].flag === false, 'Should coerce "False"');
});

test('Type coercion - null values from "null" keyword', () => {
  const csv = 'value\nnull\nNULL';
  const result = parseCSV(csv);

  assert(result.rows[0].value === null, 'Should coerce "null"');
  assert(result.rows[1].value === null, 'Should coerce "NULL"');
});

test('Type coercion - null values from empty string', () => {
  const csv = 'a,b,c\n1,,3';
  const result = parseCSV(csv);

  assert(result.rows[0].a === 1, 'First column should be 1');
  assert(result.rows[0].b === null, 'Empty field should be null');
  assert(result.rows[0].c === 3, 'Third column should be 3');
});

test('Type coercion - strings remain strings', () => {
  const csv = 'text\nhello\n123abc\nfalse_value';
  const result = parseCSV(csv);

  assert(result.rows[0].text === 'hello', 'Should keep as string');
  assert(result.rows[1].text === '123abc', 'Should keep alphanumeric as string');
  assert(result.rows[2].text === 'false_value', 'Should keep similar to bool as string');
  assert(typeof result.rows[0].text === 'string', 'Type should be string');
});

test('Type coercion - mixed types in same column', () => {
  const csv = 'data\ntext\n42\ntrue\nnull';
  const result = parseCSV(csv);

  assert(result.rows[0].data === 'text', 'String stays string');
  assert(result.rows[1].data === 42, 'Number is coerced');
  assert(result.rows[2].data === true, 'Boolean is coerced');
  assert(result.rows[3].data === null, 'Null is coerced');
});

test('Error handling - column count mismatch', () => {
  const csv = 'a,b,c\n1,2\n4,5,6,7';
  const result = parseCSV(csv);

  assert(result.rows.length === 1, 'Should skip row with wrong column count');
  assert(result.errors.length === 2, 'Should record errors');
  assert(result.errors[0].row === 2, 'First error on row 2');
  assert(result.errors[1].row === 3, 'Second error on row 3');
});

test('Error handling - unclosed quotes', () => {
  const csv = 'text\n"unclosed quote\nshould fail';
  const result = parseCSV(csv);

  assert(result.errors.length >= 1, 'Should record error for unclosed quote');
  assert(result.errors[0].message.includes('quote'), 'Error message should mention quotes');
});

test('Error handling - malformed row does not crash parser', () => {
  const csv = 'a,b\n1,2\n"broken\n5,6';
  const result = parseCSV(csv);

  assert(result.rows.length >= 1, 'Should parse valid rows despite errors');
  assert(result.errors.length > 0, 'Should record errors');
});

test('Filter - basic filtering', () => {
  const csv = 'name,age\nAlice,30\nBob,25\nCharlie,35';
  const result = parseCSV(csv);
  const filtered = result.filter(row => (row.age as number) > 26);

  assert(filtered.rows.length === 2, 'Should filter to 2 rows');
  assert(filtered.rows[0].name === 'Alice', 'Should include Alice');
  assert(filtered.rows[1].name === 'Charlie', 'Should include Charlie');
});

test('Filter - filter with index', () => {
  const csv = 'x\n1\n2\n3\n4\n5';
  const result = parseCSV(csv);
  const filtered = result.filter((row, idx) => idx % 2 === 0);

  assert(filtered.rows.length === 3, 'Should have 3 rows');
  assert(filtered.rows[0].x === 1, 'First should be 1');
  assert(filtered.rows[1].x === 3, 'Second should be 3');
  assert(filtered.rows[2].x === 5, 'Third should be 5');
});

test('Filter - filter returning no rows', () => {
  const csv = 'val\n1\n2\n3';
  const result = parseCSV(csv);
  const filtered = result.filter(row => (row.val as number) > 100);

  assert(filtered.rows.length === 0, 'Should have no rows');
  assert(filtered.headers.length === 1, 'Should preserve headers');
});

test('Filter - chaining multiple filters', () => {
  const csv = 'name,age\nAlice,30\nBob,25\nCharlie,35\nDave,28';
  const result = parseCSV(csv);
  const filtered = result
    .filter(row => (row.age as number) > 26)
    .filter(row => row.name !== 'Charlie');

  assert(filtered.rows.length === 1, 'Should have 1 row after chaining');
  assert(filtered.rows[0].name === 'Alice', 'Should be Alice');
});

test('Filter - filter preserves errors', () => {
  const csv = 'a,b\n1,2\n3';
  const result = parseCSV(csv);
  const filtered = result.filter(row => (row.a as number) > 0);

  assert(filtered.errors.length > 0, 'Should preserve errors from original parse');
});

test('Aggregation - sum basic', () => {
  const csv = 'amount\n10\n20\n30';
  const result = parseCSV(csv);
  const total = result.sum('amount');

  assert(total === 60, 'Should sum to 60');
});

test('Aggregation - sum with null values', () => {
  const csv = 'val\n5\n\n10\nnull\n15';
  const result = parseCSV(csv);
  const total = result.sum('val');

  assert(total === 30, 'Should sum only numeric values');
});

test('Aggregation - sum with strings', () => {
  const csv = 'data\nabc\n10\nxyz\n20';
  const result = parseCSV(csv);
  const total = result.sum('data');

  assert(total === 30, 'Should sum only numeric values');
});

test('Aggregation - sum with floats', () => {
  const csv = 'price\n10.5\n20.3\n15.2';
  const result = parseCSV(csv);
  const total = result.sum('price');

  assert(Math.abs(total - 46) < 0.001, 'Should sum floats correctly');
});

test('Aggregation - sum nonexistent column throws', () => {
  const csv = 'a,b\n1,2';
  const result = parseCSV(csv);

  let threw = false;
  try {
    result.sum('nonexistent');
  } catch {
    threw = true;
  }
  assert(threw, 'Should throw on nonexistent column');
});

test('Aggregation - average basic', () => {
  const csv = 'val\n10\n20\n30';
  const result = parseCSV(csv);
  const avg = result.average('val');

  assert(avg === 20, 'Average should be 20');
});

test('Aggregation - average with null values', () => {
  const csv = 'score\n100\n\n80\nnull\n60';
  const result = parseCSV(csv);
  const avg = result.average('score');

  assert(avg === 80, 'Should average only numeric values');
});

test('Aggregation - average with mixed types', () => {
  const csv = 'mixed\nabc\n10\nxyz\n20\n30';
  const result = parseCSV(csv);
  const avg = result.average('mixed');

  assert(avg === 20, 'Should average only numeric values (10+20+30)/3');
});

test('Aggregation - average of empty or non-numeric column', () => {
  const csv = 'text\nabc\nxyz\n123abc';
  const result = parseCSV(csv);
  const avg = result.average('text');

  assert(avg === 0, 'Should return 0 for non-numeric columns');
});

test('Aggregation - count basic', () => {
  const csv = 'a,b\n1,2\n3,4\n5,6';
  const result = parseCSV(csv);

  assert(result.count() === 3, 'Count should be 3');
});

test('Aggregation - count empty result', () => {
  const csv = 'x\na\nb';
  const result = parseCSV(csv);
  const filtered = result.filter(row => (row.x as string) === 'nonexistent');

  assert(filtered.count() === 0, 'Count should be 0');
});

test('Aggregation - count after filter', () => {
  const csv = 'num\n1\n2\n3\n4\n5';
  const result = parseCSV(csv);
  const filtered = result.filter(row => (row.num as number) > 2);

  assert(filtered.count() === 3, 'Count should be 3');
});

test('Aggregation - groupBy basic', () => {
  const csv = 'category,value\nA,10\nB,20\nA,15\nB,25';
  const result = parseCSV(csv);
  const groups = result.groupBy('category');

  assert(groups.size === 2, 'Should have 2 groups');
  assert(groups.has('A'), 'Should have group A');
  assert(groups.has('B'), 'Should have group B');
  assert(groups.get('A')!.length === 2, 'Group A should have 2 rows');
  assert(groups.get('B')!.length === 2, 'Group B should have 2 rows');
});

test('Aggregation - groupBy with numeric keys', () => {
  const csv = 'type,name\n1,alice\n2,bob\n1,charlie\n2,dave';
  const result = parseCSV(csv);
  const groups = result.groupBy('type');

  assert(groups.size === 2, 'Should have 2 groups');
  assert(groups.get(1)!.length === 2, 'Type 1 should have 2 rows');
  assert(groups.get(2)!.length === 2, 'Type 2 should have 2 rows');
});

test('Aggregation - groupBy with null values', () => {
  const csv = 'group,data\nA,1\n,2\nA,3\n,4';
  const result = parseCSV(csv);
  const groups = result.groupBy('group');

  assert(groups.size === 2, 'Should have 2 groups');
  assert(groups.has('A'), 'Should have group A');
  assert(groups.has(null), 'Should have null group');
  assert(groups.get('A')!.length === 2, 'Group A should have 2 rows');
});

test('Aggregation - groupBy single value', () => {
  const csv = 'status,id\nactive,1\nactive,2\nactive,3';
  const result = parseCSV(csv);
  const groups = result.groupBy('status');

  assert(groups.size === 1, 'Should have 1 group');
  assert(groups.get('active')!.length === 3, 'Should have 3 rows');
});

test('Aggregation - groupBy nonexistent column throws', () => {
  const csv = 'a\n1';
  const result = parseCSV(csv);

  let threw = false;
  try {
    result.groupBy('missing');
  } catch {
    threw = true;
  }
  assert(threw, 'Should throw on nonexistent column');
});

test('Edge case - empty input', () => {
  const result = parseCSV('');

  assert(result.rows.length === 0, 'Should have no rows');
  assert(result.headers.length === 0, 'Should have no headers');
