## Real-World Example

```javascript
const csv = `
id,name,department,salary,active
1,Alice,Engineering,120000,true
2,"Smith, Bob",Sales,85000,true
3,Charlie,Engineering,,false
4,Diana,HR,95000,TRUE
`.trim();

const result = parseCSV(csv);

// Filter active employees
const active = result.filter(r => r.active === true);
console.log(`Active: ${active.count()}`);

// Average salary (ignores empty values)
const avgSalary = result.average('salary');
console.log(`Avg salary: $${avgSalary}`);

// Group by department
const byDept = result.groupBy('department');
for (const [dept, employees] of byDept) {
  console.log(`${dept}: ${employees.length} employees`);
}

// Complex query
const engDept = result
  .filter(r => r.department === 'Engineering')
  .filter(r => r.active === true);
console.log(`Active engineers: ${engDept.count()}`);
```

