## Type Definitions (TypeScript)

```typescript
interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

interface CSVError {
  row: number;
  message: string;
}

interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row, index) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}
```

