/**
 * CSV Parser Library for TypeScript
 * Handles parsing, validation, filtering, and aggregation of CSV data
 */

/**
 * Options for CSV parsing
 */
export interface CSVOptions {
  /** Field delimiter, default: ',' */
  delimiter?: string;
  /** Quote character, default: '"' */
  quote?: string;
  /** Line separator, default: '\n' or '\r\n' */
  lineSeparator?: string;
}

/**
 * Represents a parsing error
 */
export interface CSVError {
  row: number;
  message: string;
}

/**
 * Result object returned from parsing
 */
export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

/**
 * Coerce a value to its appropriate type
 */
function coerceType(value: string): any {
  // Check for null values
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Check for boolean values
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Check for numeric values
  if (/^-?\d+(\.\d+)?$/.test(value)) {
    const num = parseFloat(value);
    if (!isNaN(num)) {
      return num;
    }
  }

  // Return as string by default
  return value;
}

/**
 * Parse a CSV string into structured data
 */
export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? (/\r\n/.test(input) ? '\r\n' : '\n');

  const errors: CSVError[] = [];
  let rows: Record<string, any>[] = [];
  let headers: string[] = [];

  if (!input || input.trim() === '') {
    return createResult([], [], errors);
  }

  // Split by line separator
  const lines = input.split(lineSeparator);

  // Parse each line into fields, handling quoted fields
  const parsedLines: string[][] = [];
  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    // Skip empty lines
    if (!line || line.trim() === '') {
      continue;
    }

    try {
      const fields = parseFields(line, delimiter, quote);
      parsedLines.push(fields);
    } catch (error) {
      errors.push({
        row: lineIndex + 1,
        message: error instanceof Error ? error.message : 'Unknown parsing error'
      });
    }
  }

  if (parsedLines.length === 0) {
    return createResult([], [], errors);
  }

  // First row is headers
  headers = parsedLines[0];

  // Parse remaining rows
  for (let i = 1; i < parsedLines.length; i++) {
    const fields = parsedLines[i];
    const row: Record<string, any> = {};

    // Check for column count mismatch
    if (fields.length !== headers.length) {
      errors.push({
        row: i + 1,
        message: `Column count mismatch: expected ${headers.length}, got ${fields.length}`
      });
      continue;
    }

    // Map fields to header names with type coercion
    for (let j = 0; j < headers.length; j++) {
      const header = headers[j];
      const value = fields[j] ?? '';
      row[header] = coerceType(value);
    }

    rows.push(row);
  }

  return createResult(rows, headers, errors);
}

/**
 * Parse a single CSV line into fields, handling quoted fields
 */
function parseFields(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let current = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = line[i + 1];

    if (char === quote) {
      if (inQuotes && nextChar === quote) {
        // Escaped quote (two quotes = one literal)
        current += quote;
        i += 2;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      // Field delimiter
      fields.push(current);
      current = '';
      i++;
    } else {
      // Regular character
      current += char;
      i++;
    }
  }

  // Add the last field
  fields.push(current);

  // Validate that quotes are properly closed
  if (inQuotes) {
    throw new Error('Unclosed quoted field');
  }

  return fields;
}

/**
 * Create a CSVResult object with methods
 */
function createResult(
  rows: Record<string, any>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult {
      const filtered = rows.filter(predicate);
      return createResult(filtered, headers, errors);
    },

    sum(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column not found: ${column}`);
      }
      return rows.reduce((acc, row) => {
        const value = row[column];
        const num = typeof value === 'number' ? value : 0;
        return acc + num;
      }, 0);
    },

    average(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column not found: ${column}`);
      }
      const numericValues = rows
        .map(row => row[column])
        .filter((v): v is number => typeof v === 'number');

      if (numericValues.length === 0) {
        return 0;
      }

      const sum = numericValues.reduce((acc, val) => acc + val, 0);
      return sum / numericValues.length;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<any, Record<string, any>[]> {
      if (!headers.includes(column)) {
        throw new Error(`Column not found: ${column}`);
      }

      const groups = new Map<any, Record<string, any>[]>();

      for (const row of rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }

      return groups;
    }
  };
}

