const byDept = result.groupBy('department');

console.log('Employees by Department:');
for (const [dept, employees] of byDept) {
  console.log(`\n${dept}:`);
  employees.forEach(emp => {
    console.log(`  - ${emp.name}: $${emp.salary}`);
  });
}

