### Example 14: GroupBy with Aggregation

```javascript
const csv = `product,quantity,price
apple,10,1.50
banana,15,0.75
apple,5,1.50
orange,8,2.00
banana,20,0.75`;

const result = parseCSV(csv);

const byProduct = result.groupBy('product');

console.log('Product Sales Summary:');
for (const [product, items] of byProduct) {
  const totalQty = items.reduce((sum, item) => sum + item.quantity, 0);
  const totalValue = items.reduce((sum, item) => sum + (item.quantity * item.price), 0);
  console.log(`${product}: ${totalQty} units, $${totalValue.toFixed(2)} total`);
}

// Output:
// Product Sales Summary:
// apple: 15 units, $22.50 total
// banana: 35 units, $26.25 total
// orange: 8 units, $16.00 total
```

