});

// Output:
// Active Subscribers: 3
// Total Monthly Revenue: $89.97
// Average Subscription: $29.99
//
// Active Subscribers:
//   - Alice Johnson (alice@example.com): $29.99
//   - Charlie Brown (charlie@example.com): $9.99
//   - Diana Prince (diana@example.com): $49.99
```

### Example 21: Sales Analysis

```javascript
const csv = `date,region,product,quantity,price,total
2024-01-01,North,Widget A,10,50.00,500.00
2024-01-02,South,Widget B,5,75.00,375.00
2024-01-03,North,Widget A,8,50.00,400.00
2024-01-04,East,Widget C,12,100.00,1200.00
2024-01-05,South,Widget B,6,75.00,450.00
2024-01-06,East,Widget C,10,100.00,1000.00`;

const result = parseCSV(csv);

// Sales by region
const byRegion = result.groupBy('region');
console.log('Sales by Region:');
for (const [region, sales] of byRegion) {
  const total = sales.reduce((sum, row) => sum + row.total, 0);
  console.log(`  ${region}: $${total.toFixed(2)} (${sales.length} sales)`);
}

// Total sales
const totalSales = result.sum('total');
const avgSale = result.average('total');
console.log(`\nTotal Sales: $${totalSales.toFixed(2)}`);
console.log(`Average Sale: $${avgSale.toFixed(2)}`);

// High-value sales
const highValue = result.filter(row => row.total > 400);
console.log(`\nHigh-Value Sales (>$400): ${highValue.count()}`);

// Output:
// Sales by Region:
//   North: $900.00 (2 sales)
//   South: $825.00 (2 sales)
//   East: $2200.00 (2 sales)
//
// Total Sales: $3925.00
// Average Sale: $654.17
//
// High-Value Sales (>$400): 3
```

### Example 22: Student Grades Analysis

```javascript
const csv = `id,name,math,english,science,overall
101,Alice,95,88,92,A
102,Bob,87,90,85,B
103,Charlie,92,85,88,B
104,Diana,78,92,80,B
105,Eve,85,88,86,B`;

const result = parseCSV(csv);

// Students with B+ average (>85)
const highPerformers = result.filter(row => {
  const avg = (row.math + row.english + row.science) / 3;
  return avg > 85;
});

console.log(`High Performers (avg > 85): ${highPerformers.count()}`);
highPerformers.rows.forEach(student => {
  const avg = ((student.math + student.english + student.science) / 3).toFixed(2);
  console.log(`  - ${student.name}: ${avg}`);
});

// Subject averages
const mathAvg = result.average('math');
const englishAvg = result.average('english');
const scienceAvg = result.average('science');

console.log('\nClass Averages:');
console.log(`  Math: ${mathAvg.toFixed(2)}`);
console.log(`  English: ${englishAvg.toFixed(2)}`);
console.log(`  Science: ${scienceAvg.toFixed(2)}`);

// Output:
// High Performers (avg > 85): 3
//   - Alice: 91.67
//   - Bob: 87.33
//   - Charlie: 88.33
//
// Class Averages:
//   Math: 87.40
//   English: 88.60
//   Science: 86.20
```

---

## Summary

These examples demonstrate:
- Basic CSV parsing
- Quoted field handling
- Type coercion
- Filtering (simple, complex, chained)
- Aggregation (sum, average, count, groupBy)
- Custom options
- Error handling
- Real-world data processing scenarios

All examples can be run with:
```bash
node -e "$(cat example.js)"
```

Or by copying the code into your project and executing it with your preferred JavaScript runtime.

