## Category 7: Type Coercion Tests

### Test 7.1: Integer Coercion
```javascript
const csv = 'num\n42\n-100\n0';
const result = parseCSV(csv);

console.assert(result.rows[0].num === 42, 'Should coerce to 42');
console.assert(result.rows[1].num === -100, 'Should coerce to -100');
console.assert(result.rows[2].num === 0, 'Should coerce to 0');
console.assert(typeof result.rows[0].num === 'number', 'Type is number');
console.log('✓ Test 7.1 passed');
```

### Test 7.2: Float Coercion
```javascript
const csv = 'value\n3.14\n-2.5\n0.0';
const result = parseCSV(csv);

console.assert(result.rows[0].value === 3.14, 'Should coerce to 3.14');
console.assert(result.rows[1].value === -2.5, 'Should coerce to -2.5');
console.assert(result.rows[2].value === 0.0, 'Should coerce to 0.0');
console.log('✓ Test 7.2 passed');
```

### Test 7.3: Boolean True Coercion
```javascript
const csv = 'flag\ntrue\nTRUE\nTrue';
const result = parseCSV(csv);

console.assert(result.rows[0].flag === true, 'true → true');
console.assert(result.rows[1].flag === true, 'TRUE → true');
console.assert(result.rows[2].flag === true, 'True → true');
console.assert(typeof result.rows[0].flag === 'boolean', 'Type is boolean');
console.log('✓ Test 7.3 passed');
```

### Test 7.4: Boolean False Coercion
```javascript
const csv = 'flag\nfalse\nFALSE\nFalse';
const result = parseCSV(csv);

console.assert(result.rows[0].flag === false, 'false → false');
console.assert(result.rows[1].flag === false, 'FALSE → false');
console.assert(result.rows[2].flag === false, 'False → false');
console.log('✓ Test 7.4 passed');
```

### Test 7.5: Null Values
```javascript
const csv = 'value\nnull\nNULL\n';
const result = parseCSV(csv);

console.assert(result.rows[0].value === null, 'null → null');
console.assert(result.rows[1].value === null, 'NULL → null');
console.assert(result.rows[2].value === null, 'empty → null');
console.log('✓ Test 7.5 passed');
```

### Test 7.6: String Values
```javascript
const csv = 'text\nhello\n123abc\nfalse_value';
const result = parseCSV(csv);

console.assert(result.rows[0].text === 'hello', 'hello stays string');
console.assert(result.rows[1].text === '123abc', 'Alphanumeric stays string');
console.assert(result.rows[2].text === 'false_value', 'false_value stays string');
console.assert(typeof result.rows[0].text === 'string', 'Type is string');
console.log('✓ Test 7.6 passed');
```

### Test 7.7: Mixed Types in Column
```javascript
const csv = 'data\ntext\n42\ntrue\nnull';
const result = parseCSV(csv);

console.assert(result.rows[0].data === 'text', 'String preserved');
console.assert(result.rows[1].data === 42, 'Number coerced');
console.assert(result.rows[2].data === true, 'Boolean coerced');
console.assert(result.rows[3].data === null, 'Null coerced');
console.log('✓ Test 7.7 passed');
```

