const result = parseCSV(csv);
const filtered = result.filter(row => row.age > 26);

console.assert(filtered.rows.length === 2, 'Should filter to 2 rows');
console.assert(filtered.rows[0].name === 'Alice', 'Alice included');
console.assert(filtered.rows[1].name === 'Charlie', 'Charlie included');
