const filtered = result.filter((row, idx) => idx % 2 === 0);

console.assert(filtered.rows.length === 3, 'Should have 3 rows');
console.assert(filtered.rows[0].x === 1, 'First is 1');
console.assert(filtered.rows[1].x === 3, 'Second is 3');
